export function applyShapeTransformations(shape, rawObject) {
  if (rawObject === undefined) {
    return {
      data: undefined,
      dropped: false,
      violations: []
    };
  }
  const primaryKey = rawObject.$primaryKey;
  const transformedProps = {};
  const requireProps = [];

  // Phase 1-3: filter (dropIfNull), apply defaults and transforms
  // Collect require props to check after cloning
  for (const prop of Object.keys(shape.__props)) {
    const config = shape.__props[prop];
    if (!config) {
      continue;
    }
    const originalValue = rawObject[prop];
    const op = config.nullabilityOp;
    switch (op.type) {
      case "dropIfNull":
        {
          if (originalValue == null) {
            return {
              data: undefined,
              dropped: true,
              violations: [{
                property: prop,
                primaryKey,
                constraint: "dropIfNull"
              }]
            };
          }
          break;
        }
      case "withDefault":
        {
          transformedProps[prop] = originalValue ?? op.defaultValue;
          break;
        }
      case "withTransform":
        {
          try {
            transformedProps[prop] = op.transform(originalValue);
          } catch (e) {
            if (process.env.NODE_ENV !== "production") {
              // eslint-disable-next-line no-console
              console.error(`Shape transform error for property "${prop}":`, e);
            }
            return {
              data: undefined,
              dropped: false,
              violations: [{
                property: prop,
                primaryKey,
                constraint: "transformError"
              }]
            };
          }
          break;
        }
      case "require":
        {
          // Collect for phase 4 - check after clone with transforms applied
          requireProps.push(prop);
          break;
        }
      case "select":
        break;
      default:
        {
          const _exhaustive = op;
        }
    }
  }

  // Clone the object with transformed properties if any were modified
  const clonedObject = Object.keys(transformedProps).length > 0 ? rawObject.$clone(transformedProps) : rawObject;

  // Phase 4: check require constraints on the transformed object.
  // This allows withDefault + require to work together correctly.
  const violations = [];
  for (const prop of requireProps) {
    const value = clonedObject[prop];
    if (value == null) {
      violations.push({
        property: prop,
        primaryKey,
        constraint: "require"
      });
    }
  }
  if (violations.length > 0) {
    return {
      data: undefined,
      dropped: false,
      violations
    };
  }
  return {
    data: clonedObject,
    dropped: false,
    violations: []
  };
}
export function applyShapeTransformationsToArray(shape, rawObjects) {
  const results = [];
  let droppedCount = 0;
  const allViolations = [];
  for (const rawObject of rawObjects) {
    const result = applyShapeTransformations(shape, rawObject);
    if (result.dropped) {
      droppedCount++;
    } else if (result.data !== undefined) {
      results.push(result.data);
    }
    allViolations.push(...result.violations);
  }
  return {
    data: results,
    droppedCount,
    violations: allViolations
  };
}